MODULE Palletize
  CONST robtarget pPick:=[[300,0,500],[1,0,0,0],[0,0,0,0],[9E9,9E9,9E9,9E9,9E9,9E9]];
  PERS num idx:=0;

  PROC main()
    FOR i FROM 1 TO 4 DO
      MoveJ pPick, v1000, fine, tool0;
      Set DO_Vacuum;
      WaitTime 0.2;
      MoveL Offs(pPick, (i-1)*200, 0, 200), v1000, z50, tool0;
      MoveL Offs(pPick, (i-1)*200, 0, 0),   v500,  fine, tool0;
      Reset DO_Vacuum;
    ENDFOR
  ENDPROC
ENDMODULE
